{% extends "_base/base.html.j2" %}


{% block title %}{{ L.doc_title }} — {{ data.name }}{% endblock %}

{% set bill = data.addresses.billing | default({}) %}
{% set ship = data.addresses.shipping | default({}) %}
{% set act = data.activitySummary | default({}) %}

{% block content %}

  <section class="cs-header" data-box="subject">
    <div class="cs-header__main">
      <h1 class="cs-header__name">{{ data.name }}</h1>
      <div class="cs-header__sub">
        {{ L.customer_no }} <strong>{{ data.customerNumber }}</strong>
        {% if data.segment %} · {{ L.segment }}: <strong>{{ data.segment }}</strong>{% endif %}
      </div>
    </div>
    {% if data.tags %}
    <div class="cs-tags">
      {% for tag in data.tags %}<span class="cs-tag">{{ tag }}</span>{% endfor %}
    </div>
    {% endif %}
  </section>

  <section class="cs-grid">

    {# Adressen #}
    <div class="cs-card cs-card--addr">
      <h2>{{ L.addr_billing }}</h2>
      <p>
        {{ bill.name | default(data.name) }}<br>
        {% if bill.street %}{{ bill.street }}<br>{% endif %}
        {{ bill.zipCode }} {{ bill.city }}<br>
        {{ bill.country }}
      </p>
    </div>

    {% if ship and (ship.street or ship.city) %}
    <div class="cs-card cs-card--addr">
      <h2>{{ L.addr_shipping }}</h2>
      <p>
        {{ ship.name | default(data.name) }}<br>
        {% if ship.street %}{{ ship.street }}<br>{% endif %}
        {{ ship.zipCode }} {{ ship.city }}<br>
        {{ ship.country }}
      </p>
    </div>
    {% endif %}

    {# Steuer + Kontakt #}
    <div class="cs-card">
      <h2>{{ L.tax_info }}</h2>
      <dl class="cs-dl">
        {% if data.vatId %}<dt>{{ L.vat_id }}</dt><dd>{{ data.vatId }}</dd>{% endif %}
        {% if data.taxId %}<dt>{{ L.tax_id }}</dt><dd>{{ data.taxId }}</dd>{% endif %}
      </dl>
    </div>

    <div class="cs-card">
      <h2>{{ L.contacts }}</h2>
      <dl class="cs-dl">
        {% if data.email %}<dt>{{ L.email }}</dt><dd>{{ data.email }}</dd>{% endif %}
        {% if data.phone %}<dt>{{ L.phone }}</dt><dd>{{ data.phone }}</dd>{% endif %}
        {% if data.mobile %}<dt>{{ L.mobile }}</dt><dd>{{ data.mobile }}</dd>{% endif %}
        {% if data.website %}<dt>{{ L.website }}</dt><dd>{{ data.website }}</dd>{% endif %}
      </dl>
    </div>

    {# Finanzen #}
    {% if data.paymentTerms or data.creditLimit %}
    <div class="cs-card">
      <h2>{{ L.finance }}</h2>
      <dl class="cs-dl">
        {% if data.paymentTerms.target %}<dt>{{ L.payment_terms }}</dt><dd>{{ data.paymentTerms.target }}</dd>{% endif %}
        {% if data.paymentTerms.method %}<dt>{{ L.payment_method }}</dt><dd>{{ data.paymentTerms.method }}</dd>{% endif %}
        {% if data.creditLimit %}<dt>{{ L.credit_limit }}</dt><dd>{{ data.creditLimit }}</dd>{% endif %}
        {% if act.openBalance %}<dt>{{ L.open_balance }}</dt><dd>{{ act.openBalance }}</dd>{% endif %}
      </dl>
    </div>
    {% endif %}

    {# Owner #}
    {% if data.salesManager or data.accountManager %}
    <div class="cs-card">
      <h2>{{ L.sales_manager }} &amp; {{ L.account_manager }}</h2>
      <dl class="cs-dl">
        {% if data.salesManager %}<dt>{{ L.sales_manager }}</dt><dd>{{ data.salesManager }}</dd>{% endif %}
        {% if data.accountManager %}<dt>{{ L.account_manager }}</dt><dd>{{ data.accountManager }}</dd>{% endif %}
      </dl>
    </div>
    {% endif %}

  </section>

  {# Ansprechpartner-Tabelle #}
  {% if data.contactPersons %}
  <section class="cs-section" aria-labelledby="cs-contacts">
    <h2 id="cs-contacts">{{ L.contact_persons }}</h2>
    <table class="cs-contacts">
      <thead>
        <tr>
          <th>{{ L.contacts }}</th>
          <th>{{ L.email }}</th>
          <th>{{ L.phone }}</th>
        </tr>
      </thead>
      <tbody>
        {% for cp in data.contactPersons %}
        <tr>
          <td><strong>{{ cp.name }}</strong>{% if cp.role %}<br><span class="cs-contacts__role">{{ cp.role }}</span>{% endif %}</td>
          <td>{{ cp.email }}</td>
          <td>{{ cp.phone }}</td>
        </tr>
        {% endfor %}
      </tbody>
    </table>
  </section>
  {% endif %}

  {# Activity-KPIs #}
  {% if act %}
  <section class="cs-section" aria-labelledby="cs-activity">
    <h2 id="cs-activity">{{ L.activity }}</h2>
    <div class="cs-kpis">
      {% if act.lastOrderDate %}
      <div class="cs-kpi"><div class="cs-kpi__label">{{ L.last_order }}</div><div class="cs-kpi__value">{{ act.lastOrderDate }}</div></div>
      {% endif %}
      {% if act.ytdRevenue %}
      <div class="cs-kpi"><div class="cs-kpi__label">{{ L.ytd_revenue }}</div><div class="cs-kpi__value">{{ act.ytdRevenue }}</div></div>
      {% endif %}
      {% if act.avgOrderValue %}
      <div class="cs-kpi"><div class="cs-kpi__label">{{ L.avg_order }}</div><div class="cs-kpi__value">{{ act.avgOrderValue }}</div></div>
      {% endif %}
      {% if act.orderCount %}
      <div class="cs-kpi"><div class="cs-kpi__label">{{ L.order_count }}</div><div class="cs-kpi__value">{{ act.orderCount }}</div></div>
      {% endif %}
    </div>
  </section>
  {% endif %}

  {% if data.notes %}
  <section class="cs-section" aria-labelledby="cs-notes">
    <h2 id="cs-notes">{{ L.notes_heading }}</h2>
    <p>{{ data.notes }}</p>
  </section>
  {% endif %}

{% endblock %}

css:
/* Customer Master Sheet — Übersicht-Layout mit Karten-Grid. Eine Seite,
   leicht scanbar. Kein Belegcharakter (keine Tabellen-Totals etc.). */

.cs-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 6mm;
  margin-bottom: 6mm;
  padding-bottom: 4mm;
  border-bottom: 0.3mm solid #d1d5db;
}
.cs-header__name {
  margin: 0;
  font-size: 18pt;
  font-weight: 700;
  letter-spacing: -0.2pt;
}
.cs-header__sub {
  margin-top: 1mm;
  font-size: 10pt;
  color: #6b7280;
}
.cs-tags {
  display: flex;
  flex-wrap: wrap;
  gap: 2mm;
  justify-content: flex-end;
}
.cs-tag {
  font-size: 8pt;
  font-weight: 600;
  padding: 0.5mm 2mm;
  border-radius: 1mm;
  background: rgba(109, 124, 255, 0.10);
  color: #4338ca;
  letter-spacing: 0.2px;
}

.cs-grid {
  display: grid;
  grid-template-columns: 1fr 1fr 1fr;
  gap: 4mm;
  margin-bottom: 6mm;
}
.cs-card {
  border: 0.3mm solid #d1d5db;
  border-radius: 1.5mm;
  padding: 4mm 5mm;
  font-size: 9.5pt;
  line-height: 1.4;
}
.cs-card h2 {
  margin: 0 0 2mm;
  font-size: 8.5pt;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.4px;
  color: #6b7280;
}
.cs-card p {
  margin: 0;
}
.cs-card--addr p {
  font-size: 10pt;
  line-height: 1.45;
}

.cs-dl {
  display: grid;
  grid-template-columns: max-content 1fr;
  gap: 1mm 3mm;
  margin: 0;
}
.cs-dl dt {
  font-size: 8pt;
  color: #6b7280;
  font-weight: 600;
}
.cs-dl dd {
  margin: 0;
  font-size: 9.5pt;
}

.cs-section {
  margin-top: 6mm;
  padding-top: 4mm;
  border-top: 0.2mm solid #e5e7eb;
}
.cs-section h2 {
  margin: 0 0 2mm;
  font-size: 10pt;
  font-weight: 700;
}

.cs-contacts {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
}
.cs-contacts thead th {
  background: #f3f4f6;
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  text-align: left;
  padding: 2mm 3mm;
  color: #374151;
  border-bottom: 0.4mm solid #6b7280;
}
.cs-contacts tbody td {
  padding: 2mm 3mm;
  border-bottom: 0.2mm solid #e5e7eb;
  vertical-align: top;
}
.cs-contacts__role {
  font-size: 8.5pt;
  color: #6b7280;
}

.cs-kpis {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 3mm;
}
.cs-kpi {
  border: 0.3mm solid #d1d5db;
  border-radius: 1.5mm;
  padding: 3mm 4mm;
}
.cs-kpi__label {
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.3px;
  text-transform: uppercase;
  color: #6b7280;
}
.cs-kpi__value {
  margin-top: 1mm;
  font-size: 13pt;
  font-weight: 600;
  color: #111827;
  font-variant-numeric: tabular-nums;
}
